-- FSI_DEMO_DB.INSURANCE.POLICYHOLDERS

CREATE OR REPLACE TABLE FSI_DEMO_DB.INSURANCE.POLICYHOLDERS (

    POLICYHOLDER_ID VARCHAR(20) NOT NULL,
    FIRST_NAME VARCHAR(50),
    LAST_NAME VARCHAR(50),
    EMAIL VARCHAR(100),
    PHONE VARCHAR(20),
    DATE_OF_BIRTH DATE,
    GENDER VARCHAR(10),
    ADDRESS_LINE1 VARCHAR(200),
    CITY VARCHAR(100),
    STATE VARCHAR(2),
    ZIP_CODE VARCHAR(10),
    COUNTRY VARCHAR(50) DEFAULT 'USA',
    OCCUPATION VARCHAR(100),
    ANNUAL_INCOME NUMBER(15,2),
    CREDIT_SCORE NUMBER(3,0),
    CUSTOMER_SINCE DATE,
    RISK_TIER VARCHAR(20),
    LIFETIME_VALUE NUMBER(15,2),
    CHURN_RISK_SCORE NUMBER(5,4),
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (POLICYHOLDER_ID)

);




